    .panel { background-color: var(--surface); border: var(--border-std); padding: 1.5rem; box-shadow: 0 4px 20px rgba(0,0,0,0.05); transition: background-color 0.3s ease, border-color 0.3s ease; }

    .panel-header { font-family: var(--font-cmd); border-bottom: var(--border-std); padding-bottom: 0.75rem; margin-bottom: 1.5rem; font-size: 1.3rem; }
    
