    button { background-color: var(--phoenix); color: #000; border: none; padding: 1rem; font-family: var(--font-cmd); font-weight: 700; text-transform: uppercase; letter-spacing: 0.5px; cursor: pointer; width: 100%; transition: all 0.2s; margin-bottom: 1rem; border-radius: 4px !important; font-size: 1rem; }
    button:hover { transform: translateY(-2px); filter: brightness(110%); }
    
    button.secondary { background-color: transparent; color: var(--signal-high); border: 1px solid var(--structure); }
    button.secondary:hover { color: var(--phoenix); border-color: var(--phoenix); transform: translateY(-2px); }
    
    button.success { background-color: var(--terminal); color: var(--void); }
